#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
const int N=2010,Mod=1e9+7;int dp[N][N],n,s,t;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
int main()
{
	scanf("%d%d%d",&n,&s,&t);
	dp[0][0]=1;int c=0;rep(1,n-1,i)
	{
		c+=(i==s||i==t);
		rep(0,i,j)
		{
			if(i==s||i==t)
			{
				DN(dp[i][j]+=dp[i-1][j]);
				if(j)dp[i][j-1]=(1ll*dp[i-1][j]*j+dp[i][j-1])%Mod;
			}
			else
			{
				dp[i][j]=(1ll*dp[i-1][j+1]*(j+1)*(j+c)+dp[i][j])%Mod;
				if(j)DN(dp[i][j]+=dp[i-1][j-1]);
			}
		}
	}
	printf("%d\n",dp[n-1][0]);
}
